const response = $.steps.listBuckets.response;
const buckets = Array.isArray(response) ? response : (response.data || response.buckets || []);
let compiled = '';
let bucketCount = 0;

buckets.forEach((b, i) => {
  compiled += 'Bucket ' + (i + 1) + ':\n';
  compiled += '  ID: ' + (b.id || 'N/A') + '\n';
  compiled += '  Name: ' + (b.name || 'N/A') + '\n';
  compiled += '  Public: ' + (b.public || false) + '\n';
  compiled += '  Created: ' + (b.created_at || 'N/A') + '\n';
  compiled += '  Updated: ' + (b.updated_at || 'N/A') + '\n\n';
  bucketCount++;
});

return { compiled, bucketCount, buckets };

const d = $.steps.compileBucketData.output;
const question = $.input.question;
const projectRef = $.input.projectRef;

let prompt = 'You are a Supabase storage expert assistant. The user has a question about their Supabase Storage files and buckets.\n\n';
prompt += 'PROJECT REF: ' + projectRef + '\n';
prompt += 'TOTAL BUCKETS: ' + d.bucketCount + '\n\n';
prompt += '=== STORAGE BUCKETS ===\n' + (d.compiled || 'No buckets found.') + '\n\n';
prompt += 'USER QUESTION: ' + question + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Answer the user question based on the storage data provided\n';
prompt += '- Provide insights about storage organization, naming conventions, and usage patterns\n';
prompt += '- Suggest best practices for Supabase storage if relevant\n';
prompt += '- If the data is insufficient to fully answer, explain what additional info would help\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "comprehensive answer to the question",\n';
prompt += '  "insights": ["insight 1", "insight 2"],\n';
prompt += '  "recommendations": ["recommendation 1"],\n';
prompt += '  "storageOverview": { "totalBuckets": ' + d.bucketCount + ', "publicBuckets": 0, "privateBuckets": 0 },\n';
prompt += '  "additionalContext": "any helpful extra context"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, insights: [], recommendations: [], storageOverview: {}, additionalContext: '' }; }

const ai = $.steps.parseAI.output;
const d = $.steps.compileBucketData.output;
const question = $.input.question;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Supabase File Chat', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Buckets:*\n' + d.bucketCount },
  { type: 'mrkdwn', text: '*Project:*\n' + $.input.projectRef }
] });
blocks.push({ type: 'divider' });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:*\n' + question } });
blocks.push({ type: 'divider' });

const answer = (ai.answer || 'No answer available.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Answer:*\n' + answer } });

if (ai.insights && ai.insights.length > 0) {
  blocks.push({ type: 'divider' });
  let iText = '*Insights:*\n';
  ai.insights.forEach((ins, i) => { iText += (i + 1) + '. ' + ins + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: iText.slice(0, 1800) } });
}

if (ai.recommendations && ai.recommendations.length > 0) {
  blocks.push({ type: 'divider' });
  let rText = '*Recommendations:*\n';
  ai.recommendations.forEach((rec, i) => { rText += (i + 1) + '. ' + rec + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: rText.slice(0, 1800) } });
}

if (ai.additionalContext) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '_' + ai.additionalContext.slice(0, 1800) + '_' } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Supabase + Claude AI | One CLI' }] });

const fallbackText = 'Supabase File Chat: ' + (ai.answer || '').slice(0, 100);
return { blocks, fallbackText };
